+namespace DocSummary.Services;
+
+/// <summary>
+/// Extractive summarization service that scores sentences by word frequency
+/// and returns the top-ranked ones in their original order.
+/// </summary>
+public class DocumentSummarizationService
+{
+    private static readonly char[] SentenceTerminators = ['.', '!', '?'];
+
+    public string Summarize(string text, int maxSentences)
+    {
+        var sentences = SplitIntoSentences(text);
+
+        if (sentences.Count <= maxSentences)
+        {
+            return string.Join(" ", sentences);
+        }
+
+        var wordFrequencies = BuildWordFrequencies(sentences);
+        var scored = ScoreSentences(sentences, wordFrequencies);
+
+        // Pick the top-scoring sentences but preserve their original order.
+        var topIndices = scored
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .Select(s => s.Index)
+            .Order()
+            .ToList();
+
+        return string.Join(" ", topIndices.Select(i => sentences[i]));
+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        var sentences = new List<string>();
+        int start = 0;
+
+        for (int i = 0; i < text.Length; i++)
+        {
+            if (SentenceTerminators.Contains(text[i]))
+            {
+                // Include the terminator in the sentence.
+                var sentence = text[start..(i + 1)].Trim();
+                if (sentence.Length > 0)
+                {
+                    sentences.Add(sentence);
+                }
+                start = i + 1;
+            }
+        }
+
+        // Capture any trailing text that lacks a terminator.
+        var remaining = text[start..].Trim();
+        if (remaining.Length > 0)
+        {
+            sentences.Add(remaining);
+        }
+
+        return sentences;
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in GetWords(sentence))
+            {
+                frequencies.TryGetValue(word, out int count);
+                frequencies[word] = count + 1;
+            }
+        }
+
+        return frequencies;
+    }
+
+    private static List<(int Index, double Score)> ScoreSentences(
+        List<string> sentences,
+        Dictionary<string, int> wordFrequencies)
+    {
+        var scored = new List<(int Index, double Score)>();
+
+        for (int i = 0; i < sentences.Count; i++)
+        {
+            var words = GetWords(sentences[i]);
+            if (words.Length == 0)
+            {
+                scored.Add((i, 0));
+                continue;
+            }
+
+            double score = words.Sum(w => wordFrequencies.GetValueOrDefault(w, 0)) / (double)words.Length;
+            scored.Add((i, score));
+        }
+
+        return scored;
+    }
+
+    private static string[] GetWords(string text) =>
+        text.Split([' ', '\t', '\r', '\n'], StringSplitOptions.RemoveEmptyEntries)
+            .Select(w => w.Trim('.', ',', ';', ':', '!', '?', '"', '\'', '(', ')'))
+            .Where(w => w.Length > 0)
+            .ToArray();
+
+    public static int CountWords(string text) =>
+        text.Split([' ', '\t', '\r', '\n'], StringSplitOptions.RemoveEmptyEntries).Length;
+}
